struct Position: Identifiable, Codable {
    let id = UUID()
    let symbol: String
    var quantity: Int
    var avgCost: Double
    var lastPrice: Double
    
    var marketValue: Double { Double(quantity) * lastPrice }
    var costBasis: Double { Double(quantity) * avgCost }
    var unrealizedPL: Double { marketValue - costBasis }
}

struct Portfolio: Codable {
    var cash: Double
    var positions: [Position]
    var marketValue: Double
    var netLiquidation: Double
    var dayPL: Double
    
    static let defaultSymbols = ["AAPL", "MSFT", "NVDA", "AMZN"]
    static let mock = Portfolio(
        cash: 25000,
        positions: [
            Position(symbol: "AAPL", quantity: 20, avgCost: 180.10, lastPrice: 191.12),
            Position(symbol: "MSFT", quantity: 10, avgCost: 420.00, lastPrice: 412.55)
        ],
        marketValue: 9800,
        netLiquidation: 34800,
        dayPL: 320.50
    )
    
    mutating func apply(order: TradeOrder, fillPrice: Double) {
        let value = fillPrice * Double(order.quantity)
        switch order.side {
        case .buy:
            cash -= value
            if let idx = positions.firstIndex(where: { $0.symbol == order.symbol }) {
                let existing = positions[idx]
                let totalShares = existing.quantity + order.quantity
                let newAvg = ((existing.avgCost * Double(existing.quantity)) + value) / Double(totalShares)
                positions[idx].quantity = totalShares
                positions[idx].avgCost = newAvg
                positions[idx].lastPrice = fillPrice
            } else {
                positions.append(Position(symbol: order.symbol, quantity: order.quantity, avgCost: fillPrice, lastPrice: fillPrice))
            }
        case .sell:
            cash += value
            if let idx = positions.firstIndex(where: { $0.symbol == order.symbol }) {
                positions[idx].quantity -= order.quantity
                positions[idx].lastPrice = fillPrice
                if positions[idx].quantity <= 0 {
                    positions.remove(at: idx)
                }
            }
        }
        recalc()
    }
    
    mutating func recalc() {
        marketValue = positions.reduce(0) { $0 + $1.marketValue }
        netLiquidation = cash + marketValue
        dayPL = positions.reduce(0) { $0 + ($1.lastPrice - $1.avgCost) * Double($1.quantity) }
    }
}

