protocol APIRequest {
    var path: String { get }
    var method: String { get }
    var body: Data? { get }
    var headers: [String: String] { get }
}

final class TradingAPIClient {
    private let baseURL: URL
    private let apiKey: String
    private let apiSecret: String
    private let session: URLSession
    
    init(baseURL: URL, apiKey: String, apiSecret: String) {
        self.baseURL = baseURL
        self.apiKey = apiKey
        self.apiSecret = apiSecret
        let config = URLSessionConfiguration.default
        config.timeoutIntervalForRequest = 10
        config.requestCachePolicy = .reloadIgnoringLocalCacheData
        self.session = URLSession(configuration: config)
    }
    
    func ping() async throws {
        _ = try await send(request: BasicRequest(path: "/ping"))
    }
    
    func fetchQuotes(symbols: [String]) async throws -> [StockQuote] {
        let req = BasicRequest(path: "/quotes?symbols=\(symbols.joined(separator: ","))")
        let data = try await send(request: req)
        if let decoded = try? JSONDecoder().decode([StockQuote].self, from: data) {
            return decoded
        }
        return StockQuote.mockData.filter { symbols.contains($0.symbol) }
    }
    
    func fetchPortfolio() async throws -> Portfolio {
        let data = try await send(request: BasicRequest(path: "/portfolio"))
        if let decoded = try? JSONDecoder().decode(Portfolio.self, from: data) {
            return decoded
        }
        return Portfolio.mock
    }
    
    func placeOrder(order: TradeOrder) async throws -> TradeOrder {
        let encoder = JSONEncoder()
        let data = try encoder.encode(order)
        let req = BasicRequest(path: "/orders", method: "POST", body: data)
        let response = try await send(request: req)
        if let decoded = try? JSONDecoder().decode(TradeOrder.self, from: response) {
            return decoded
        }
        var simulated = order
        simulated.status = .filled
        simulated.filledQuantity = order.quantity
        simulated.averageFillPrice = 0
        return simulated
    }
    
    private func send(request: BasicRequest) async throws -> Data {
        let url = baseURL.appendingPathComponent(request.path.trimmingCharacters(in: CharacterSet(charactersIn: "/")))
        var urlRequest = URLRequest(url: url)
        urlRequest.httpMethod = request.method
        urlRequest.httpBody = request.body
        urlRequest.setValue("application/json", forHTTPHeaderField: "Content-Type")
        urlRequest.setValue(apiKey, forHTTPHeaderField: "X-API-KEY")
        urlRequest.setValue(sign(request: request), forHTTPHeaderField: "X-SIGNATURE")
        request.headers.forEach { urlRequest.setValue($1, forHTTPHeaderField: $0) }
        let (data, response) = try await session.data(for: urlRequest)
        guard let http = response as? HTTPURLResponse, 200..<300 ~= http.statusCode else {
            throw URLError(.badServerResponse)
        }
        return data
    }
    
    private func sign(request: BasicRequest) -> String {
        let payload = "\(request.method)|\(request.path)|\(request.body?.base64EncodedString() ?? "")|\(apiSecret)"
        let hash = SHA256.hash(data: Data(payload.utf8))
        return hash.compactMap { String(format: "%02x", $0) }.joined()
    }
}

struct BasicRequest: APIRequest {
    let path: String
    let method: String
    let body: Data?
    let headers: [String: String]
    
    init(path: String, method: String = "GET", body: Data? = nil, headers: [String: String] = [:]) {
        self.path = path
        self.method = method
        self.body = body
        self.headers = headers
    }
}

final class TradeExecutionEngine {
    private let apiClient: TradingAPIClient
    
    init(apiClient: TradingAPIClient) {
        self.apiClient = apiClient
    }
    
    func execute(order: TradeOrder) async throws -> TradeOrder {
        var validated = order
        guard validated.quantity > 0 else { throw TradeError.invalidQuantity }
        validated.status = .submitted
        
        let executed = try await apiClient.placeOrder(order: validated)
        var final = executed
        if final.status == .submitted { final.status = .filled }
        if final.filledQuantity == 0 { final.filledQuantity = final.quantity }
        if final.averageFillPrice == nil {
            final.averageFillPrice = final.limitPrice ?? 0
        }
        return final
    }
}

enum TradeError: Error, LocalizedError {
    case invalidQuantity
    
    var errorDescription: String? {
        switch self {
        case .invalidQuantity: return "Quantity must be greater than zero."
        }
    }
}

final class SecureStore {
    static let shared = SecureStore()
    private init() {}
    
    func save(_ value: String, key: String) -> Bool {
        let data = Data(value.utf8)
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecValueData as String: data
        ]
        SecItemDelete(query as CFDictionary)
        return SecItemAdd(query as CFDictionary, nil) == errSecSuccess
    }
    
    func load(key: String) -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        var result: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        guard status == errSecSuccess, let data = result as? Data else { return nil }
        return String(data: data, encoding: .utf8)
    }
}

extension Double {
    var currencyString: String {
        NumberFormatter.currency.string(from: NSNumber(value: self)) ?? "$0.00"
    }
    var percentString: String {
        NumberFormatter.percent.string(from: NSNumber(value: self / 100.0)) ?? "0.00%"
    }
}

extension NumberFormatter {
    static let currency: NumberFormatter = {
        let f = NumberFormatter()
        f.numberStyle = .currency
        f.maximumFractionDigits = 2
        return f
    }()
    static let percent: NumberFormatter = {
        let f = NumberFormatter()
        f.numberStyle = .percent
        f.maximumFractionDigits = 2
        return f
    }()
}